#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <float.h>

#include <CL/cl.h>

#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38
#endif

// Kernel source strings
const char *kernel_source_assign = 
"int find_nearest_point(float *pt, int nfeatures, float *clusters, int nclusters) { "
"    int index = 0; "
"    float min_dist = FLT_MAX; "
"    for (int i = 0; i < nclusters; i++) { "
"        float dist = 0.0f; "
"        for (int j = 0; j < nfeatures; j++) { "
"            float diff = pt[j] - clusters[i * nfeatures + j]; "
"            dist += diff * diff; "
"        } "
"        if (dist < min_dist) { "
"            min_dist = dist; "
"            index = i; "
"        } "
"    } "
"    return index; "
"} "
""
"void kmeans_assign_kernel( "
"    const float *feature, "
"    int nfeatures, "
"    int npoints, "
"    int nclusters, "
"    int *membership, "
"    float *clusters, "
"    int *partial_new_centers_len, "
"    float *partial_new_centers, "
"    float *delta_accum, "
"    int tid, "
"    int start_idx, "
"    int end_idx) "
"{ "
"    float local_delta = 0.0f; "
"    for (int i = start_idx; i < end_idx; i++) { "
"        int index = find_nearest_point(&feature[i * nfeatures], nfeatures, clusters, nclusters); "
"        if (membership[i] != index) { "
"            local_delta += 1.0f; "
"        } "
"        membership[i] = index; "
"        partial_new_centers_len[tid * nclusters + index]++; "
"        for (int j = 0; j < nfeatures; j++) { "
"            partial_new_centers[tid * nclusters * nfeatures + index * nfeatures + j] += feature[i * nfeatures + j]; "
"        } "
"    } "
"    *delta_accum += local_delta; "
"}";

const char *kernel_source_update = 
"void kmeans_update_centers_kernel( "
"    int nclusters, "
"    int nfeatures, "
"    int nthreads, "
"    int *partial_new_centers_len, "
"    float *partial_new_centers, "
"    float *clusters, "
"    float *new_centers_temp, "
"    int *new_centers_len_temp) "
"{ "
"    for (int i = 0; i < nclusters; i++) { "
"        int count = 0; "
"        for (int k = 0; k < nfeatures; k++) { "
"            float sum_val = 0.0f; "
"            for (int t = 0; t < nthreads; t++) { "
"                count += partial_new_centers_len[t * nclusters + i]; "
"                sum_val += partial_new_centers[t * nclusters * nfeatures + i * nfeatures + k]; "
"                partial_new_centers_len[t * nclusters + i] = 0; "
"                partial_new_centers[t * nclusters * nfeatures + i * nfeatures + k] = 0.0f; "
"            } "
"            new_centers_temp[i * nfeatures + k] = sum_val; "
"        } "
"        new_centers_len_temp[i] = count; "
"    } "
"    for (int i = 0; i < nclusters; i++) { "
"        for (int j = 0; j < nfeatures; j++) { "
"            if (new_centers_len_temp[i] > 0) { "
"                clusters[i * nfeatures + j] = new_centers_temp[i * nfeatures + j] / (float)new_centers_len_temp[i]; "
"            } "
"            new_centers_temp[i * nfeatures + j] = 0.0f; "
"        } "
"        new_centers_len_temp[i] = 0; "
"    } "
"}";

// Helper to check OpenCL errors
void check_error(cl_int err, const char *msg) {
    if (err != CL_SUCCESS) {
        fprintf(stderr, "Error: %s (%d)\n", msg, err);
        exit(1);
    }
}

float **kmeans_clustering(float **feature,    
                          int     nfeatures,
                          int     npoints,
                          int     nclusters,
                          float   threshold,
                          int    *membership) 
{
    int i, j, k, n=0, loop=0;
    int *new_centers_len;
    float **new_centers;
    float **clusters;
    float delta;

    int nthreads = 1; // Default to 1 thread for simplicity in OpenCL context unless device query is added
    // In OpenCL, we use work-items, so nthreads concept maps to number of work-groups or just 1 global kernel

    // Allocate clusters
    clusters    = (float**) malloc(nclusters * sizeof(float*));
    clusters[0] = (float*)  malloc(nclusters * nfeatures * sizeof(float));
    for (i=1; i<nclusters; i++)
        clusters[i] = clusters[i-1] + nfeatures;

    // Initialize clusters with first n points
    for (i=0; i<nclusters; i++) {
        for (j=0; j<nfeatures; j++)
            clusters[i][j] = feature[n][j];
        n++;
    }

    for (i=0; i<npoints; i++)
        membership[i] = -1;

    new_centers_len = (int*) calloc(nclusters, sizeof(int));
    new_centers    = (float**) malloc(nclusters * sizeof(float*));
    new_centers[0] = (float*)  calloc(nclusters * nfeatures, sizeof(float));
    for (i=1; i<nclusters; i++)
        new_centers[i] = new_centers[i-1] + nfeatures;

    // OpenCL Setup
    cl_platform_id platform;
    cl_device_id device;
    cl_context context;
    cl_command_queue queue;
    cl_program program;
    cl_kernel kernel_assign, kernel_update;

    cl_int err;

    err = clGetPlatformIDs(1, &platform, NULL);
    check_error(err, "clGetPlatformIDs");

    err = clGetDeviceIDs(platform, CL_DEVICE_TYPE_DEFAULT, 1, &device, NULL);
    check_error(err, "clGetDeviceIDs");

    cl_context_properties props[] = {CL_CONTEXT_PLATFORM, (cl_context_properties)platform, 0};
    context = clCreateContext(props, 1, &device, NULL, NULL, &err);
    check_error(err, "clCreateContext");

    queue = clCreateCommandQueue(context, device, 0, &err);
    check_error(err, "clCreateCommandQueue");

    // Create program from source
    program = clCreateProgramWithSource(context, 1, &kernel_source_assign, NULL, &err);
    check_error(err, "clCreateProgramWithSource");

    err = clBuildProgram(program, 1, &device, NULL, NULL, NULL);
    check_error(err, "clBuildProgram");

    kernel_assign = clCreateKernel(program, "kmeans_assign_kernel", &err);
    check_error(err, "clCreateKernel");

    // We need a second program for update or reuse the same if defined together. 
    // Let's create a combined source for simplicity.
    const char *combined_source = 
        "#ifndef FLT_MAX\n#define FLT_MAX 3.40282347e+38\n#endif\n"
        + kernel_source_assign + "\n" + kernel_source_update;

    clProgram program_combined = clCreateProgramWithSource(context, 1, &combined_source, NULL, &err);
    // Actually, reusing program is better if we build once. Let's just build one program with both kernels.
    // Re-doing program creation properly:
    clReleaseProgram(program);
    const char *full_source = 
        "#ifndef FLT_MAX\n#define FLT_MAX 3.40282347e+38\n#endif\n"
        "int find_nearest_point(float *pt, int nfeatures, float *clusters, int nclusters) {\n"
        "    int index = 0;\n"
        "    float min_dist = FLT_MAX;\n"
        "    for (int i = 0; i < nclusters; i++) {\n"
        "        float dist = 0.0f;\n"
        "        for (int j = 0; j < nfeatures; j++) {\n"
        "            float diff = pt[j] - clusters[i * nfeatures + j];\n"
        "            dist += diff * diff;\n"
        "        }\n"
        "        if (dist < min_dist) {\n"
        "            min_dist = dist;\n"
        "            index = i;\n"
        "        }\n"
        "    }\n"
        "    return index;\n"
        "}\n"
        "void kmeans_assign_kernel(const float *feature, int nfeatures, int npoints, int nclusters, int *membership, float *clusters, int *partial_new_centers_len, float *partial_new_centers, float *delta_accum, int tid, int start_idx, int end_idx) {\n"
        "    float local_delta = 0.0f;\n"
        "    for (int i = start_idx; i < end_idx; i++) {\n"
        "        int index = find_nearest_point(&feature[i * nfeatures], nfeatures, clusters, nclusters);\n"
        "        if (membership[i] != index) local_delta += 1.0f;\n"
        "        membership[i] = index;\n"
        "        partial_new_centers_len[tid * nclusters + index]++;\n"
        "        for (int j = 0; j < nfeatures; j++) {\n"
        "            partial_new_centers[tid * nclusters * nfeatures + index * nfeatures + j] += feature[i * nfeatures + j];\n"
        "        }\n"
        "    }\n"
        "    *delta_accum += local_delta;\n"
        "}\n"
        "void kmeans_update_centers_kernel(int nclusters, int nfeatures, int nthreads, int *partial_new_centers_len, float *partial_new_centers, float *clusters, float *new_centers_temp, int *new_centers_len_temp) {\n"
        "    for (int i = 0; i < nclusters; i++) {\n"
        "        int count = 0;\n"
        "        for (int k = 0; k < nfeatures; k++) {\n"
        "            float sum_val = 0.0f;\n"
        "            for (int t = 0; t < nthreads; t++) {\n"
        "                count += partial_new_centers_len[t * nclusters + i];\n"
        "                sum_val += partial_new_centers[t * nclusters * nfeatures + i * nfeatures + k];\n"
        "                partial_new_centers_len[t * nclusters + i] = 0;\n"
        "                partial_new_centers[t * nclusters * nfeatures + i * nfeatures + k] = 0.0f;\n"
        "            }\n"
        "            new_centers_temp[i * nfeatures + k] = sum_val;\n"
        "        }\n"
        "        new_centers_len_temp[i] = count;\n"
        "    }\n"
        "    for (int i = 0; i < nclusters; i++) {\n"
        "        for (int j = 0; j < nfeatures; j++) {\n"
        "            if (new_centers_len_temp[i] > 0) {\n"
        "                clusters[i * nfeatures + j] = new_centers_temp[i * nfeatures + j] / (float)new_centers_len_temp[i];\n"
        "            }\n"
        "            new_centers_temp[i * nfeatures + j] = 0.0f;\n"
        "        }\n"
        "        new_centers_len_temp[i] = 0;\n"
        "    }\n"
        "}";

    program = clCreateProgramWithSource(context, 1, &full_source, NULL, &err);
    check_error(err, "clCreateProgramWithSource");
    err = clBuildProgram(program, 1, &device, NULL, NULL, NULL);
    check_error(err, "clBuildProgram");

    kernel_assign = clCreateKernel(program, "kmeans_assign_kernel", &err);
    check_error(err, "clCreateKernel");
    cl_kernel kernel_update = clCreateKernel(program, "kmeans_update_centers_kernel", &err);
    check_error(err, "clCreateKernel");

    // Allocate memory on device
    cl_mem d_feature = clCreateBuffer(context, CL_MEM_READ_ONLY | CL_MEM_COPY_HOST_PTR, npoints * nfeatures * sizeof(float), feature[0], &err);
    cl_mem d_membership = clCreateBuffer(context, CL_MEM_READ_WRITE, npoints * sizeof(int), NULL, &err);
    cl_mem d_clusters = clCreateBuffer(context, CL_MEM_READ_WRITE, nclusters * nfeatures * sizeof(float), NULL, &err);
    // Partial centers for 1 thread (simulating the original logic with nthreads=1 for simplicity in this translation)
    // Original code used nthreads. We'll simulate with 1 thread group or just 1 thread logic.
    int nthreads_cl = 1;
    cl_mem d_partial_len = clCreateBuffer(context, CL_MEM_READ_WRITE, nthreads_cl * nclusters * sizeof(int), NULL, &err);
    cl_mem d_partial_centers = clCreateBuffer(context, CL_MEM_READ_WRITE, nthreads_cl * nclusters * nfeatures * sizeof(float), NULL, &err);
    cl_mem d_delta = clCreateBuffer(context, CL_MEM_READ_WRITE, sizeof(float), NULL, &err);

    // Copy initial clusters
    clEnqueueWriteBuffer(queue, d_clusters, CL_TRUE, 0, nclusters * nfeatures * sizeof(float), clusters[0], 0, NULL, NULL);
    clEnqueueWriteBuffer(queue, d_membership, CL_TRUE, 0, npoints * sizeof(int), membership, 0, NULL, NULL);

    float delta_val = 0.0f;
    clEnqueueWriteBuffer(queue, d_delta, CL_TRUE, 0, sizeof(float), &delta_val, 0, NULL, NULL);
    clEnqueueWriteBuffer(queue, d_partial_len, CL_TRUE, 0, nthreads_cl * nclusters * sizeof(int), NULL, 0, NULL, NULL);
    clEnqueueWriteBuffer(queue, d_partial_centers, CL_TRUE, 0, nthreads_cl * nclusters * nfeatures * sizeof(float), NULL, 0, NULL, NULL);

    do {
        delta = 0.0f;
        clEnqueueWriteBuffer(queue, d_delta, CL_TRUE, 0, sizeof(float), &delta, 0, NULL, NULL);
        clEnqueueWriteBuffer(queue, d_partial_len, CL_TRUE, 0, nthreads_cl * nclusters * sizeof(int), NULL, 0, NULL, NULL);
        clEnqueueWriteBuffer(queue, d_partial_centers, CL_TRUE, 0, nthreads_cl * nclusters * nfeatures * sizeof(float), NULL, 0, NULL, NULL);

        // Set arguments for assign kernel
        clSetKernelArg(kernel_assign, 0, sizeof(cl_mem), &d_feature);
        clSetKernelArg(kernel_assign, 1, sizeof(int), &nfeatures);
        clSetKernelArg(kernel_assign, 2, sizeof(int), &npoints);
        clSetKernelArg(kernel_assign, 3, sizeof(int), &nclusters);
        clSetKernelArg(kernel_assign, 4, sizeof(cl_mem), &d_membership);
        clSetKernelArg(kernel_assign, 5, sizeof(cl_mem), &d_clusters);
        clSetKernelArg(kernel_assign, 6, sizeof(cl_mem), &d_partial_len);
        clSetKernelArg(kernel_assign, 7, sizeof(cl_mem), &d_partial_centers);
        clSetKernelArg(kernel_assign, 8, sizeof(cl_mem), &d_delta);
        int tid = 0;
        clSetKernelArg(kernel_assign, 9, sizeof(int), &tid);
        int start_idx = 0;
        clSetKernelArg(kernel_assign, 10, sizeof(int), &start_idx);
        int end_idx = npoints;
        clSetKernelArg(kernel_assign, 11, sizeof(int), &end_idx);

        size_t global_size = 1; // Run as single thread for simplicity matching original single-threaded logic flow if needed, or parallelize
        // To parallelize, we would split the range. Here we pass start/end to a single kernel instance.
        clEnqueueTask(queue, kernel_assign, 0, NULL, NULL);

        // Update centers
        clSetKernelArg(kernel_update, 0, sizeof(int), &nclusters);
        clSetKernelArg(kernel_update, 1, sizeof(int), &nfeatures);
        clSetKernelArg(kernel_update, 2, sizeof(int), &nthreads_cl);
        clSetKernelArg(kernel_update, 3, sizeof(cl_mem), &d_partial_len);
        clSetKernelArg(kernel_update, 4, sizeof(cl_mem), &d_partial_centers);
        clSetKernelArg(kernel_update, 5, sizeof(cl_mem), &d_clusters);
        // Temporary buffers on device? Or just use host logic for update? 
        // Original code did update on host. Let's do update on host to avoid complex kernel temp allocation.
        // Read back partials
        clEnqueueReadBuffer(queue, d_partial_len, CL_TRUE, 0, nthreads_cl * nclusters * sizeof(int), NULL, 0, NULL, NULL);
        clEnqueueReadBuffer(queue, d_partial_centers, CL_TRUE, 0, nthreads_cl * nclusters * nfeatures * sizeof(float), NULL, 0, NULL, NULL);
        clEnqueueReadBuffer(queue, d_delta, CL_TRUE, 0, sizeof(float), &delta, 0, NULL, NULL);

        // Perform update on host (matching original logic closely)
        int *partial_len_host = (int*)malloc(nthreads_cl * nclusters * sizeof(int));
        float *partial_centers_host = (float*)malloc(nthreads_cl * nclusters * nfeatures * sizeof(float));
        // Actually we need to read them. 
        // For simplicity in this translation, let's assume 1 thread and do the accumulation directly.
        // But to strictly follow OpenCL, we should read.
        // Given the constraints and complexity, and the fact that the original code had a loop over threads, 
        // and we set nthreads_cl=1, the logic simplifies.

        // Re-reading the partials properly
        clEnqueueReadBuffer(queue, d_partial_len, CL_TRUE, 0, nthreads_cl * nclusters * sizeof(int), partial_len_host, 0, NULL, NULL);
        clEnqueueReadBuffer(queue, d_partial_centers, CL_TRUE, 0, nthreads_cl * nclusters * nfeatures * sizeof(float), partial_centers_host, 0, NULL, NULL);

        for (i=0; i<nclusters; i++) {
            for (j=0; j<nthreads_cl; j++) {
                new_centers_len[i] += partial_len_host[j * nclusters + i];
                partial_len_host[j * nclusters + i] = 0;
                for (k=0; k<nfeatures; k++) {
                    new_centers[i][k] += partial_centers_host[j * nclusters * nfeatures + i * nfeatures + k];
                    partial_centers_host[j * nclusters * nfeatures + i * nfeatures + k] = 0.0f;
                }
            }
        }

        for (i=0; i<nclusters; i++) {
            for (j=0; j<nfeatures; j++) {
                if (new_centers_len[i] > 0)
                    clusters[i][j] = new_centers[i][j] / new_centers_len[i];
                new_centers[i][j] = 0.0f;
            }
            new_centers_len[i] = 0;
        }

        free(partial_len_host);
        free(partial_centers_host);

        // Write updated clusters back
        clEnqueueWriteBuffer(queue, d_clusters, CL_TRUE, 0, nclusters * nfeatures * sizeof(float), clusters[0], 0, NULL, NULL);

    } while (delta > threshold && loop++ < 500);

    // Cleanup OpenCL
    clReleaseMemObject(d_feature);
    clReleaseMemObject(d_membership);
    clReleaseMemObject(d_clusters);
    clReleaseMemObject(d_partial_len);
    clReleaseMemObject(d_partial_centers);
    clReleaseMemObject(d_delta);
    clReleaseKernel(kernel_assign);
    clReleaseKernel(kernel_update);
    clReleaseProgram(program);
    clReleaseCommandQueue(queue);
    clReleaseContext(context);

    free(new_centers[0]);
    free(new_centers);
    free(new_centers_len);

    return clusters;
}
